from dagster import asset
import pandas as pd

@asset
def raw_orders() -> pd.DataFrame:
    """Load raw orders from a CSV file."""
    return pd.read_csv("s3://my-bucket/orders/raw.csv")

@asset
def cleaned_orders(raw_orders: pd.DataFrame) -> pd.DataFrame:
    """Remove nulls and duplicates from raw orders."""
    return (
        raw_orders
        .dropna(subset=["order_id", "customer_id"])
        .drop_duplicates(subset=["order_id"])
    )

@asset
def daily_revenue(cleaned_orders: pd.DataFrame) -> pd.DataFrame:
    """Aggregate revenue by day."""
    return (
        cleaned_orders
        .groupby("order_date")["amount"]
        .sum()
        .reset_index()
        .rename(columns={"amount": "total_revenue"})
    )

