    })

@asset(group_name="transformation")
def purchase_events(raw_events: pd.DataFrame) -> pd.DataFrame:
    """Filter only purchase events."""
    return raw_events[raw_events["event_type"] == "purchase"].copy()

@asset(group_name="transformation")
def revenue_by_user(purchase_events: pd.DataFrame) -> pd.DataFrame:
    """Aggregate total revenue per user."""
    return (
        purchase_events
        .groupby("user_id")["amount"]
        .sum()
        .reset_index()
        .rename(columns={"amount": "total_revenue"})
    )

