from dagster_snowflake_pandas import SnowflakePandasIOManager
from dagster_dbt import dbt_assets, DbtCliResource, DbtProject

daily = DailyPartitionsDefinition(start_date="2023-01-01")

@asset(
    partitions_def=daily,
    retry_policy=RetryPolicy(max_retries=3, delay=30, backoff=ExponentialBackoff()),
    group_name="extract"
)
def raw_orders(context: AssetExecutionContext, postgres_db) -> pd.DataFrame:
    date = context.partition_key
    context.log.info(f"Extracting orders for {date}")
    return postgres_db.query(
        f"SELECT * FROM orders WHERE order_date = '{date}'"
    )

@asset(partitions_def=daily, group_name="transform")
def enriched_orders(raw_orders: pd.DataFrame, postgres_db) -> pd.DataFrame:
    customers = postgres_db.query("SELECT * FROM customers")
    return raw_orders.merge(customers, on="customer_id", how="left")

@asset(partitions_def=daily, group_name="transform")
def daily_revenue_summary(enriched_orders: pd.DataFrame) -> pd.DataFrame:
    return (
        enriched_orders
        .groupby(["order_date", "region"])["order_total"]
        .agg(["sum", "count", "mean"])
        .reset_index()
    )

