from dagster import asset_check, AssetCheckResult

@asset_check(asset=daily_revenue_summary)
def revenue_is_non_negative(daily_revenue_summary: pd.DataFrame) -> AssetCheckResult:
    passed = (daily_revenue_summary["sum"] >= 0).all()
    return AssetCheckResult(
        passed=bool(passed),
        metadata={"min_revenue": float(daily_revenue_summary["sum"].min())}
    )

